package ru.memearena.tournament.application; import org.springframework.stereotype.*; import org.springframework.transaction.annotation.*; import ru.memearena.scout.application.AchievementService; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.tournament.domain.*; import ru.memearena.tournament.infrastructure.*; import java.time.*; import java.util.*; import java.util.stream.*;
@Service public class TournamentProgressionService{ private final TournamentRepository tournaments; private final TournamentEntryRepository entries; private final TournamentMatchRepository matches; private final MemeTournamentStatsRepository stats; private final AchievementService achievements; private final MemeRepository memes; private final Clock clock; private final TournamentProperties props; public TournamentProgressionService(TournamentRepository t,TournamentEntryRepository e,TournamentMatchRepository m,MemeTournamentStatsRepository s,AchievementService a,MemeRepository memes,Clock c,TournamentProperties p){tournaments=t;entries=e;matches=m;stats=s;achievements=a;this.memes=memes;clock=c;props=p;} @Transactional public Tournament advance(UUID id){Tournament t=tournaments.findById(id).orElseThrow(); if(t.status==TournamentStatus.COMPLETED)return t; Instant now=Instant.now(clock); List<TournamentMatch> round=matches.findByTournamentIdAndRoundNumberOrderByMatchNumber(t.id,t.currentRound); if(round.stream().anyMatch(m->m.status==TournamentMatchStatus.ACTIVE&&m.endsAt.isAfter(now))) return t; Map<UUID,Integer> seed=entries.findByTournamentIdOrderBySeed(t.id).stream().collect(Collectors.toMap(e->e.memeId,e->e.seed)); List<UUID> winners=new ArrayList<>(); for(TournamentMatch m:round){ if(m.status==TournamentMatchStatus.ACTIVE){m.winnerMemeId=m.leftVotes==m.rightVotes?(seed.get(m.leftMemeId)<seed.get(m.rightMemeId)?m.leftMemeId:m.rightMemeId):(m.leftVotes>m.rightVotes?m.leftMemeId:m.rightMemeId); m.status=TournamentMatchStatus.COMPLETED; m.completedAt=now; m.updatedAt=now;} if(m.winnerMemeId!=null) winners.add(m.winnerMemeId); UUID loser=null; if(m.leftMemeId!=null&& !m.leftMemeId.equals(m.winnerMemeId)) loser=m.leftMemeId; if(m.rightMemeId!=null&& !m.rightMemeId.equals(m.winnerMemeId)) loser=m.rightMemeId; if(loser!=null) entries.findByTournamentIdAndMemeId(t.id,loser).ifPresent(e->{e.eliminatedRound=t.currentRound;}); }
 if(winners.size()<=1){t.status=TournamentStatus.COMPLETED;t.winnerMemeId=winners.isEmpty()?null:winners.get(0);t.completedAt=now;t.updatedAt=now;finishStats(t,now);return t;} if(!matches.existsByTournamentIdAndRoundNumber(t.id,t.currentRound+1)){for(int i=0;i<winners.size();i+=2)matches.save(new TournamentMatch(UUID.randomUUID(),t.id,t.currentRound+1,(i/2)+1,winners.get(i),i+1<winners.size()?winners.get(i+1):null,i+1<winners.size()?TournamentMatchStatus.ACTIVE:TournamentMatchStatus.BYE,now,now.plus(Duration.ofHours(props.roundDurationHours())),now));} t.currentRound++; t.updatedAt=now; return t;} private void finishStats(Tournament t,Instant now){var es=entries.findByTournamentIdOrderBySeed(t.id); for(var e:es){var st=stats.findById(e.memeId).orElseGet(()->new MemeTournamentStats(e.memeId,now)); if(e.finalPosition!=null) continue; st.participations++; if(e.memeId.equals(t.winnerMemeId)){st.wins++; st.finals++; e.finalPosition=1;} else if(e.eliminatedRound!=null&&e.eliminatedRound>=4){st.finals++; e.finalPosition=2;} else e.finalPosition=99; st.updatedAt=now; stats.save(st); memes.findById(e.memeId).map(x->x.getUploaderId()).filter(java.util.Objects::nonNull).ifPresent(u->{achievements.unlock(u,"TOURNAMENT_PARTICIPANT",now); if(e.finalPosition!=null&&e.finalPosition<=2)achievements.unlock(u,"TOURNAMENT_FINALIST",now); if(e.finalPosition!=null&&e.finalPosition==1)achievements.unlock(u,"TOURNAMENT_WINNER",now);});} }}
